-- ============================================================================
-- REALTRUM Onboarding — Пример IBG-инжекций (overlays под роли)
-- Демонстрация: один урок про Skills из Claude 101 +
--               role-specific overlays для 4 ролей.
--
-- ВАЖНО: Контент САМОГО урока (transcript_en, transcript_ru, theory_ru)
-- НЕ МЕНЯЕТСЯ. Меняется только то, что добавляется (overlays + variants).
--
-- Запускать ПОСЛЕ 005_seed_roles_levels_templates.sql
-- ============================================================================

-- ----------------------------------------------------------------------------
-- ROLE OVERLAYS для урока "Работа со Skills"
-- ----------------------------------------------------------------------------
-- Логика: REALTRUM при рендере урока берёт текст из ob_lessons,
-- а потом ДОБАВЛЯЕТ блок "## Применение для вашей роли" из ob_lesson_role_overlays
-- по role_id из user assessment.
-- ----------------------------------------------------------------------------

DO $$
DECLARE
    v_lesson_skills_id UUID;
    v_lesson_first_conv_id UUID;
    v_lesson_projects_id UUID;
    v_lesson_use_cases_id UUID;
BEGIN
    SELECT id INTO v_lesson_skills_id FROM ob_lessons WHERE slug = 'skills';
    SELECT id INTO v_lesson_first_conv_id FROM ob_lessons WHERE slug = 'first-conversation';
    SELECT id INTO v_lesson_projects_id FROM ob_lessons WHERE slug = 'projects';
    SELECT id INTO v_lesson_use_cases_id FROM ob_lessons WHERE slug = 'use-cases-by-role';

    -- =========================================================================
    -- OVERLAY: Урок Skills × Sales Agent
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_skills_id,
        r.id,
        E'## Skills для агента по продажам IBG\n\nКаждая повторяющаяся коммуникация с клиентом — кандидат на отдельный Skill. Минимальный набор для агента:\n\n### 1. ibg-client-followup\nДля писем клиентам, замолчавшим на 3+ дня после получения КП.\n**Триггер в description:** "follow-up клиенту, клиент молчит, напомнить о себе".\n**Что внутри:** структура мягкого возврата в диалог + reference на прошлое общение + новый ингредиент (фото со стройки, обновление цены).\n\n### 2. ibg-kp-generator\nДля генерации коммерческих предложений по проекту под конкретного клиента.\n**Триггер:** "сделай КП по проекту X для клиента Y".\n**Что внутри:** структура КП (проект → юнит → преимущества → цена → следующий шаг) + tone of voice + 2 примера хороших КП.\n\n### 3. ibg-objection-cold-feet\nДля отработки возражения "ещё подумаю / не уверен".\n**Триггер:** "клиент думает, отрабатываем возражение, нужно убедить".\n**Что внутри:** LPMAMA-подход + список конкретных причин для решения + примеры закрытий.\n\n### 4. ibg-language-bridge\nДля перевода и адаптации сообщений между языками клиента и агента (RU/EN/CN).\n**Триггер:** "переведи сообщение клиента, ответь на языке клиента".\n**Что внутри:** правила тональности по языкам + культурные нюансы.',
        E'**Совет под продажи:** Skills — это твоя "записная книжка эксперта", которая всегда с тобой. Раз в неделю записывай одну ситуацию, которую отработал хорошо, превращай в Skill. Через 3 месяца у тебя будет персональная экспертная система, которой нет ни у кого в команде.\n\nГлавная ошибка агентов: писать Skill в стиле "помоги с письмами клиентам". Это не сработает — описание слишком общее. Скоупь конкретно: "для клиентов, которые получили КП и молчат больше 3 дней".'
    FROM ob_roles r WHERE r.slug = 'sales-agent';

    -- =========================================================================
    -- OVERLAY: Урок Skills × Rental Agent
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_skills_id,
        r.id,
        E'## Skills для агента по аренде IBG\n\nВ аренде особенно много повторяющихся коммуникаций — каждая стоит отдельного Skill.\n\n### 1. ibg-rental-checkin\nИнструкции по заселению для гостя.\n**Триггер:** "пришли гайд по заселению, как добраться, ключи, правила".\n**Что внутри:** структура гайда (адрес → как добраться → код от двери → wifi → правила → контакт).\n\n### 2. ibg-rental-house-rules\nПравила проживания для гостей разных культур.\n**Триггер:** "правила для гостей, что можно/нельзя в квартире".\n**Что внутри:** разные тоны для русских / европейских / азиатских гостей.\n\n### 3. ibg-rental-complaint-resolution\nОбработка жалоб (шумные соседи, поломки, конфликты).\n**Триггер:** "гость жалуется, конфликт, проблема в квартире".\n**Что внутри:** алгоритм деэскалации + варианты компенсации + когда вовлекать собственника.\n\n### 4. ibg-rental-owner-update\nОбновление собственнику о состоянии квартиры.\n**Триггер:** "написать собственнику отчёт, обновление по квартире".\n**Что внутри:** структура (текущий гость → срок → загрузка → инциденты → следующая бронь).',
        E'**Совет под аренду:** в аренде разные категории гостей требуют разного тона: туристы на 3 дня — короткие чёткие гайды, долгосрочники — подробнее и лично. Заведи минимум 2 версии Skills для каждого типа коммуникации.\n\nКлючевая боль аренды — собственники, которые задают одни и те же вопросы. Skill ibg-rental-owner-update решает эту боль: сделал шаблон отчёта, и каждый раз генеришь готовое сообщение за 30 секунд вместо 10 минут.'
    FROM ob_roles r WHERE r.slug = 'rental-agent';

    -- =========================================================================
    -- OVERLAY: Урок Skills × Marketing
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_skills_id,
        r.id,
        E'## Skills для маркетинга IBG\n\nМаркетинг — это конвейер форматов. Skill = один формат + tone of voice.\n\n### 1. ibg-reels-script\nГенерация скриптов Reels по фреймворку Hook → Retain → Reward (Hormozi).\n**Триггер:** "напиши скрипт Reels, видео для Instagram".\n**Что внутри:** структура (3-секундный hook → 15-30 секунд contento → CTA) + примеры удачных Reels IBG.\n\n### 2. ibg-telegram-post\nПосты для Telegram-канала IBG.\n**Триггер:** "пост в TG, Telegram-канал, для подписчиков".\n**Что внутри:** длина 800-1200 знаков + конкретный hook + одна цифра/факт + CTA.\n\n### 3. ibg-threads-post\nКороткие посты для Threads (другой формат — короче и personal).\n**Триггер:** "Threads, build in public, личный пост".\n**Что внутри:** 1-3 предложения, личная интонация, провокация или инсайт.\n\n### 4. ibg-landing-copy\nКопирайтинг для лендингов проектов.\n**Триггер:** "копирайт лендинг, страница проекта, продающий текст".\n**Что внутри:** структура (hero → 3 бенефита → социальное доказательство → CTA) + примеры IBG.\n\n### 5. ibg-ad-creative-variants\nГенерация 5+ вариантов креатива для A/B теста.\n**Триггер:** "варианты для A/B, тестируем рекламу".\n**Что внутри:** инструкция держать единый смысл, но менять hook / CTA / визуальный посыл.',
        E'**Совет под маркетинг:** Skill = твоя бренд-биб­лия в действии. Не пиши tone of voice "дружелюбный, экспертный" — это не работает. Пиши: "никогда не используем слова \"уникальный\", \"эксклюзивный\". Используем конкретные цифры. Никогда не стартуем с \"В этом посте я расскажу\". Стартуем с провокации или вопроса."\n\nМощный приём: после того как написал Skill — прогоняй через него 5 старых постов, которые ты считаешь успешными. Если Skill их воспроизводит — он работает. Если нет — Skill недонастроен.'
    FROM ob_roles r WHERE r.slug = 'marketing';

    -- =========================================================================
    -- OVERLAY: Урок Skills × QC
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_skills_id,
        r.id,
        E'## Skills для контроля качества IBG\n\nQC работает с рубриками — это идеальный кандидат для Skills (рубрика = постоянный набор критериев).\n\n### 1. ibg-qc-call-scoring\nОценка звонка по LPMAMA-рубрике.\n**Триггер:** "оцени звонок, провели разбор, скоринг агента".\n**Что внутри:** 5 блоков LPMAMA (Listen-Probe-Match-Add-Message-Action) с весами + критерии 1-5 по каждому.\n\n### 2. ibg-qc-feedback-coaching\nГенерация feedback-сообщения агенту с конкретными примерами и рекомендациями.\n**Триггер:** "feedback агенту, разбор для агента, что улучшить".\n**Что внутри:** структура (что хорошо → что улучшить → конкретный пример из разговора → что сделать на следующем звонке).\n\n### 3. ibg-qc-pattern-detection\nПоиск паттернов в наборе звонков (что часто пропускается, где общие проблемы).\n**Триггер:** "анализ нескольких звонков, паттерны ошибок, типичные проблемы".\n**Что внутри:** инструкция извлекать паттерны, не отдельные ошибки + формат вывода (топ-3 повторяющихся проблем).\n\n### 4. ibg-qc-weekly-summary\nЕженедельный сводный отчёт по агенту.\n**Триггер:** "недельный отчёт по агенту, сводка за неделю".\n**Что внутри:** структура (количество звонков → средний score → топ-сильные стороны → топ-зоны роста → рекомендация на следующую неделю).',
        E'**Совет под QC:** ваша работа — это Skills в чистом виде. Каждая рубрика, каждый шаблон фидбека — это Skill, который масштабирует вашу экспертизу.\n\nЦель — построить полный Skill-стек QC к концу курса. После этого QC-team может оценивать в 3-4 раза больше звонков с тем же составом, не теряя в качестве.\n\nКонтекст IBG: эти Skills — основа для будущей AI QC системы (см. IBG_AI_QC_Spec). Если соберёшь их хорошо — это готовая бизнес-логика, которую Innovations потом обернёт в n8n workflow.'
    FROM ob_roles r WHERE r.slug = 'qc';

    -- =========================================================================
    -- OVERLAY: Урок Projects × Sales Agent
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_projects_id,
        r.id,
        E'## Project для агента по продажам IBG\n\n### Минимальная структура Project "Sales [твоё имя]"\n\n**Системные инструкции:**\n```\nКонтекст: Я агент IBG Property — [имя]. Продаю новостройки в \nПхукете и на Бали для иностранных инвесторов от $300K.\n\nМои основные сегменты клиентов: [перечислить — например, \nрусскоязычные инвесторы 35-50 лет, англоязычные из Азии, \nкитайские покупатели через посредников].\n\nЯзык ответа: всегда отвечай на языке исходного запроса. \nПо умолчанию русский. Английский — American business style.\n\nТон писем клиентам: дружелюбный, экспертный, без воды. \nКороткие абзацы 3-4 предложения.\n\nИспользуй файлы из Knowledge для актуальной информации о \nпроектах и ценах. Не выдумывай цифры — спрашивай меня, если \nкаталог не покрывает.\n```\n\n**Knowledge (что загрузить):**\n1. Каталог проектов IBG 2026 (PDF/Excel)\n2. Прайс-лист на текущий месяц\n3. Шаблоны хороших писем (5-10 примеров)\n4. FAQ клиентов: 20 типичных вопросов + эталонные ответы\n5. Карта Пхукета с зонами по доходности\n\n**Чаты внутри Project (примеры):**\n- "Шаблоны WhatsApp по проекту Layan"\n- "КП для David Tan (Сингапур)"\n- "Follow-ups этой недели"\n- "Перевод переписки с китайским клиентом"',
        E'**Совет:** не пытайся сделать один Project на всё. Сделай по одному на каждый ключевой проект, который продаёшь, если их 2-3 ведущих. Так легче поддерживать актуальные цены и материалы.\n\nКлюч к успешному Project — обновлённое Knowledge. Раз в неделю — 5 минут на обновление прайса и каталога. Иначе Claude будет подкидывать устаревшие цифры в письмах клиентам.'
    FROM ob_roles r WHERE r.slug = 'sales-agent';

    -- =========================================================================
    -- OVERLAY: Урок First Conversation × Newcomer-paths (для всех нетехнических ролей)
    -- Делаем по одному примеру: для агента и для маркетинга
    -- =========================================================================
    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_first_conv_id,
        r.id,
        E'## Ваш первый разговор с Claude — для агента\n\nПопробуйте начать с конкретной рабочей задачи, которую делаете каждый день. Например:\n\n```\nВы: Привет. Я агент в IBG, продаю недвижимость в Пхукете. \nКлиент написал в WhatsApp на английском: "Hey, looking for \ninvestment property under $500K with rental yield 8%+. \nWhat do you have?"\n\nПомоги составить ответ на английском.\n\nClaude: [предложит draft ответа]\n\nВы: Хорошо, но добавь конкретный проект — Layan Verde, \n2-bedroom за $420K, доходность 9% по программе застройщика.\n\nClaude: [улучшит ответ]\n\nВы: Сократи в 2 раза. И добавь приглашение на показ \nна следующей неделе.\n\nClaude: [финальная версия]\n```\n\nЗа 2 минуты вы получили готовый ответ на сложный запрос клиента.',
        E'**Совет для агента:** не тратьте свой первый чат на тестовые вопросы вроде "что ты умеешь?". Берите конкретного клиента из CRM, реальный запрос, и отрабатывайте. За 30 минут получите первое реальное "ого, это работает".'
    FROM ob_roles r WHERE r.slug = 'sales-agent';

    INSERT INTO ob_lesson_role_overlays (lesson_id, role_id, extra_examples_ru, role_specific_tips_ru)
    SELECT
        v_lesson_first_conv_id,
        r.id,
        E'## Ваш первый разговор с Claude — для маркетинга\n\nПопробуйте начать с генерации хука для Reels или поста:\n\n```\nВы: Помоги придумать 5 хуков для Reels про инвестиции в \nнедвижимость на Пхукете для русскоязычной аудитории. \nЦелевая — инвесторы 35-50, ищут пассивный доход.\n\nClaude: [предложит 5 вариантов]\n\nВы: Слабовато. Сделай их провокационнее, чтобы был эффект \n"стоп-скролл". И добавь конкретные цифры.\n\nClaude: [улучшит]\n\nВы: Хук №3 хороший. Развей его в полный скрипт Reels \nдо 30 секунд по фреймворку Hook → Retain → Reward.\n```\n\nЗа 5 минут вы получили готовый скрипт.',
        E'**Совет для маркетинга:** Claude хорошо работает с фреймворками. Загрузите в первый чат описание Hook → Retain → Reward или AIDA — и попросите применять. Получите более структурированные результаты.'
    FROM ob_roles r WHERE r.slug = 'marketing';

    -- =========================================================================
    -- ВАРИАНТЫ ПРАКТИЧЕСКИХ ЗАДАНИЙ ПОД РОЛИ
    -- =========================================================================
    -- Базовое упражнение в ob_exercises остаётся универсальным.
    -- Здесь — варианты ТЕМЫ под конкретные роли.
    -- =========================================================================

    -- Найдём базовое упражнение из урока 7 (Skills)
    DECLARE
        v_exercise_skill_id UUID;
        v_exercise_first_conv_id UUID;
        v_exercise_projects_id UUID;
    BEGIN
        SELECT e.id INTO v_exercise_skill_id
        FROM ob_exercises e
        JOIN ob_lessons l ON l.id = e.lesson_id
        WHERE l.slug = 'skills' AND e.slug = 'practical-7-1';

        IF v_exercise_skill_id IS NOT NULL THEN
            -- Вариант для Sales Agent
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, example_solution_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-client-followup для писем клиентам, которые замолчали на 3+ дня после получения вашего КП.\n\nSkill должен включать:\n1. Frontmatter с конкретным description (триггерные фразы про follow-up)\n2. Структуру сообщения: приветствие → reference на прошлое общение → новый ингредиент → лёгкий CTA → подпись\n3. Тон: не извиняющийся, не агрессивный, экспертный\n4. Что НЕ делать (срочность, "извините за беспокойство", повтор того же)\n5. Минимум 1 пример хорошего follow-up на русском и 1 на английском',
                E'Контекст IBG: вы продаёте новостройки иностранным инвесторам. После отправки КП ~40% клиентов замолкают. Хороший follow-up возвращает 15-20% из них в диалог. Плохой — добавляет давления и теряет навсегда.',
                E'Готовое решение лежит в обзорной части урока (см. полный пример Skill в основном theory_ru). Адаптируйте под свой стиль и конкретные проекты, которые вы продаёте чаще всего.',
                ARRAY['Follow-up клиентам, замолчавшим на 3+ дня']
            FROM ob_roles r WHERE r.slug = 'sales-agent';

            -- Вариант для Rental Agent
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-rental-checkin для генерации инструкций по заселению для гостя.\n\nSkill должен включать:\n1. Frontmatter с триггерами ("пришли гайд по заселению", "инструкция для гостя", "как заселиться")\n2. Структуру: адрес → как добраться → код от двери → wifi → правила → контакт\n3. Адаптацию под язык гостя (русский / английский / упрощённый английский для не-носителей)\n4. Тон: дружелюбный, чёткий, без воды\n5. Минимум 1 пример инструкции',
                E'Контекст IBG: вы сдаёте квартиры в Пхукете гостям разных национальностей. Каждое заселение — отдельное сообщение в WhatsApp с инструкциями. Большинство гостей задают одни и те же вопросы. Хороший Skill экономит 10-15 минут на каждое заселение.',
                ARRAY['Координация заселений и выселений', 'Ответы арендаторам на повторяющиеся вопросы']
            FROM ob_roles r WHERE r.slug = 'rental-agent';

            -- Вариант для Marketing
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-reels-script для генерации скриптов Reels по фреймворку Hook → Retain → Reward.\n\nSkill должен включать:\n1. Frontmatter с триггерами ("скрипт Reels", "видео для Instagram")\n2. Структуру скрипта: 3-секундный hook → 15-30 секунд содержания → CTA в конце\n3. Tone of voice IBG (по вашим брендбукам)\n4. Что НЕ делать (общие фразы, "уникальный", скучные начала)\n5. Минимум 2 примера хороших скриптов из вашего опыта',
                E'Контекст IBG: вы делаете Reels для каналов IBG в Instagram и TikTok. Цель — привлекать внимание иностранных инвесторов и владельцев недвижимости. Цикл: пишете 3-5 скриптов в неделю, снимаете, постите, анализируете engagement.',
                ARRAY['Производство контента для соцсетей (Reels, посты, stories)']
            FROM ob_roles r WHERE r.slug = 'marketing';

            -- Вариант для QC
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-qc-call-scoring для оценки звонка агента по LPMAMA-рубрике.\n\nSkill должен включать:\n1. Frontmatter с триггерами ("оцени звонок", "разбор звонка агента")\n2. Все 6 блоков LPMAMA (Listen-Probe-Match-Add-Message-Action) с весами и критериями оценки 1-5\n3. Формат вывода: оценка по блокам + общий score + 3 ключевых наблюдения\n4. Что НЕ делать (общие "хорошо/плохо", без конкретных моментов)\n5. Пример оценки реального гипотетического звонка',
                E'Контекст IBG: вы оцениваете 20-30 звонков в неделю. Сейчас на каждый — 15-20 минут. Skill позволит за 5 минут получить структурированную оценку, которую вы дополняете нюансами.',
                ARRAY['Прослушивание и оценка звонков по рубрике', 'Составление детального фидбека агентам']
            FROM ob_roles r WHERE r.slug = 'qc';

            -- Вариант для HR
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-resume-screening для скрининга резюме кандидатов на роль агента по продажам IBG.\n\nSkill должен включать:\n1. Frontmatter с триггерами ("оцени резюме", "screening резюме", "подходит ли кандидат")\n2. Критерии оценки: опыт продаж, опыт в недвижимости, языки, soft skills, red flags\n3. Формат вывода: оценка 1-10 + сильные стороны + слабые стороны + рекомендация (интервью / отказ / уточнить)\n4. Что НЕ делать (предвзятость по полу/возрасту/национальности — этого избегать!)\n5. Пример оценки гипотетического резюме',
                E'Контекст IBG: цель — найти 50 англоязычных агентов за 8 месяцев. Поток резюме большой, ручной скрининг — bottleneck.',
                ARRAY['Скрининг резюме и составление шорт-листов']
            FROM ob_roles r WHERE r.slug = 'hr';

            -- Вариант для Call Center
            INSERT INTO ob_exercise_role_variants (exercise_id, role_id, instructions_override_ru, context_override_ru, suggested_pain_points)
            SELECT
                v_exercise_skill_id,
                r.id,
                E'Напишите Skill ibg-cold-script-fb-leads для скриптов первого контакта с холодными лидами из Facebook Ads.\n\nSkill должен включать:\n1. Frontmatter с триггерами ("скрипт холодного звонка", "первый контакт с лидом", "FB лид")\n2. Структуру скрипта: открытие → проверка контекста (что увидел в рекламе) → 3 квалифицирующих вопроса → CTA на следующий шаг\n3. Адаптацию под язык лида (русский / английский / mixed)\n4. Что НЕ делать (длинная речь, продавать в первом контакте)\n5. Минимум 2 варианта скрипта (для разной аудитории)',
                E'Контекст IBG: вы обрабатываете 30-50 лидов в день из Facebook Ads. Цель первого звонка — квалификация (не продажа): выяснить бюджет, сроки, тип покупки (для жизни/инвест), и передать горячих агенту.',
                ARRAY['Скрипты первичных контактов под разные источники лидов']
            FROM ob_roles r WHERE r.slug = 'call-center';
        END IF;
    END;

END $$;

-- ============================================================================
-- ГОТОВО.
-- Покрытие demo: 1 урок (Skills) × 4 роли overlays + 6 ролей exercise variants
--               + 2 урока с overlays для 2 ролей.
--
-- Полный seed (все уроки × все роли) — следующий шаг (большой объём).
-- Этого demo достаточно, чтобы:
-- 1. Видеть, как работает механика role-aware рендера
-- 2. Тестировать UI REALTRUM
-- 3. Дальше расширять по шаблону
-- ============================================================================

-- VIEW для проверки покрытия overlays
CREATE OR REPLACE VIEW v_ob_overlay_coverage AS
SELECT
    l.title_ru AS lesson,
    string_agg(r.title_ru, ', ') AS roles_with_overlays,
    COUNT(DISTINCT o.role_id) AS overlay_count
FROM ob_lessons l
LEFT JOIN ob_lesson_role_overlays o ON o.lesson_id = l.id
LEFT JOIN ob_roles r ON r.id = o.role_id
GROUP BY l.id, l.title_ru, l.sort_order
ORDER BY l.sort_order;
